// Variables globales
let pasoActual = 1;
const totalPasos = 5; // Ahora son 5 pasos antes de confirmación
let datosReserva = {
    servicios: [],
    precios: {
        "Corte": 15000,
        "Teñido": 40000,
        "Alisado": 30000
    },
    reserva: 5000,
    fecha: null,
    horario: null,
    nombre: null,
    email: null,
    telefono: null,
    observacion: null
};

let usuarioActual = null;

// Elementos DOM
const elementos = {
    progreso: document.getElementById('progreso'),
    btnAnterior: document.querySelector('.btn-anterior'),
    btnSiguiente: document.querySelector('.btn-siguiente'),
    pasos: document.querySelectorAll('.paso'),
    // Elementos de resumen
    resumenNombre: document.getElementById('cliente-nombre'),
    resumenEmail: document.getElementById('cliente-email'),
    resumenTelefono: document.getElementById('cliente-telefono'),
    resumenServicio: document.getElementById('servicio-seleccionado'),
    resumenFecha: document.getElementById('fecha-seleccionada'),
    resumenHorario: document.getElementById('horario-seleccionado'),
    resumenObservacion: document.getElementById('observacion-texto')
};

// Usar las referencias globales
const auth = window.firebaseAuth;
// const provider = window.firebaseProvider;

// Inicialización
document.addEventListener('DOMContentLoaded', () => {
  // Verificar si hay usuario en LocalStorage
  const usuarioLS = localStorage.getItem('usuario');
  if (usuarioLS) {
    const user = JSON.parse(usuarioLS);
    actualizarUIUsuario(user);
  }

  inicializarEventos();
  actualizarInterfaz();
  inicializarAuth();
  inicializarDisponibilidadDemo();
});

// Funciones principales
function inicializarEventos() {
    // Navegación
    elementos.btnAnterior.addEventListener('click', retrocederPaso);
    elementos.btnSiguiente.addEventListener('click', avanzarPaso);
    
    // Selección de servicios (manejo delegado)
    document.querySelectorAll('.flotante.servicio').forEach(servicio => {
        servicio.addEventListener('click', function() {
            this.classList.toggle('seleccionado');
            actualizarServiciosSeleccionados();
        });
    });
    
    // Fechas y horarios
    document.querySelectorAll('.flotante.fecha').forEach(fecha => {
        fecha.addEventListener('click', function() {
            seleccionarElemento(this, 'fecha');
        });
    });
    
    document.querySelectorAll('.flotante.horario').forEach(horario => {
        horario.addEventListener('click', function() {
            if (!this.classList.contains('ocupado')) {
                seleccionarElemento(this, 'horario');
            } else {
                alert('Este horario ya está ocupado. Por favor selecciona otro.');
            }
        });
    });
    
    // Validación en tiempo real
    document.getElementById('nombre')?.addEventListener('input', validarNombre);
    document.getElementById('email')?.addEventListener('input', validarEmail);
    document.getElementById('telefono')?.addEventListener('input', validarTelefono);
}

function calcularSubtotal() {
    const subtotal = datosReserva.servicios.reduce((total, servicio) => total + servicio.precio, 0);
    document.getElementById('subtotal').textContent = `$${subtotal.toLocaleString()}`;
    return subtotal;
}

function actualizarServiciosSeleccionados() {
    const serviciosSeleccionados = document.querySelectorAll('.flotante.servicio.seleccionado');
    datosReserva.servicios = Array.from(serviciosSeleccionados).map(serv => {
        return {
            nombre: serv.getAttribute('data-servicio'),
            precio: datosReserva.precios[serv.getAttribute('data-servicio')]
        };
    });
    
    // Actualizar contador
    document.getElementById('contador-servicios').textContent = datosReserva.servicios.length;
    
    // Ocultar error si hay selección
    if (datosReserva.servicios.length > 0) {
        document.getElementById('error-servicio').classList.remove('visible');
    }
    
    // Calcular y mostrar subtotal
    calcularSubtotal();
}

async function avanzarPaso() {
    if (pasoActual >= totalPasos) return;
    
    try {
        if (!validarPaso(pasoActual)) {
            return;
        }

        if (pasoActual === 4) {
            guardarDatosFormulario();
            actualizarResumen();
        }

        pasoActual++;
        actualizarInterfaz();
        
        // Autocompletar después de avanzar al paso 4
        if (pasoActual === 4 && usuarioActual) {
            autocompletarFormulario(usuarioActual);
        }
    } catch (error) {
        console.error('Error al avanzar paso:', error);
    }
}

function retrocederPaso() {
    if (pasoActual > 1) {
        pasoActual--;
        actualizarInterfaz();
    }
}

function actualizarInterfaz() {
    actualizarPasos();
    actualizarProgreso();
    actualizarBotones();
}

async function simularReserva() {
    // Simular un retardo de red
    await new Promise(resolve => setTimeout(resolve, 1500));
    
    // Simular éxito o error aleatorio para demostración
    const exito = Math.random() > 0; // 100% de éxito
    mostrarConfirmacion(exito);
    
    // En un sistema real, aquí iría la conexión con Firebase
    if (exito) {
        console.log('Reserva simulada:', datosReserva);
    } else {
        console.log('Error simulado en reserva');
    }
}

// Simular disponibilidad de turnos
function inicializarDisponibilidadDemo() {
    const fechas = document.querySelectorAll('.flotante.fecha');
    const horarios = document.querySelectorAll('.flotante.horario');
    
    // Marcar algunos horarios como ocupados aleatoriamente (para demo)
    horarios.forEach(horario => {
        if (Math.random() > 0.8) { // 20% de probabilidad de estar ocupado
            horario.classList.add('ocupado');
            horario.addEventListener('click', () => {
                alert('Este horario ya está ocupado. Por favor selecciona otro.');
            });
        }
    });
}

// Funciones de apoyo
function actualizarPasos() {
    elementos.pasos.forEach((paso, index) => {
        paso.classList.toggle('activo', index + 1 === pasoActual);
    });
}

function actualizarProgreso() {
    const porcentaje = (pasoActual / totalPasos) * 100;
    elementos.progreso.style.width = `${porcentaje}%`;
}

function actualizarBotones() {
    // Botón anterior
    if (pasoActual === 1) {
        elementos.btnAnterior.classList.remove('activo');
    } else {
        elementos.btnAnterior.classList.add('activo');
    }
    
    // Limpiar eventos previos del botón siguiente
    elementos.btnSiguiente.replaceWith(elementos.btnSiguiente.cloneNode(true));
    elementos.btnSiguiente = document.querySelector('.btn-siguiente');
    
    // Configurar botón siguiente según el paso actual
    if (pasoActual === totalPasos) {
        elementos.btnSiguiente.classList.add('btn-reserva');
        elementos.btnSiguiente.textContent = 'Reservar';
        elementos.btnSiguiente.addEventListener('click', async () => {
            await simularReserva();
        });
    } else {
        elementos.btnSiguiente.classList.remove('btn-reserva');
        elementos.btnSiguiente.innerHTML = `
            <svg class="flecha" viewBox="0 0 24 24" width="24" height="24">
                <path d="M8.59 16.59L13.17 12 8.59 7.41 10 6l6 6-6 6-1.41-1.41z" fill="ffffff"/>
            </svg>
        `;
        elementos.btnSiguiente.addEventListener('click', avanzarPaso);
    }
}

function seleccionarElemento(elemento, tipo) {
    // Si ya está seleccionado y es servicio, deseleccionar
    if (elemento.classList.contains('seleccionado') && tipo === 'servicio') {
        elemento.classList.remove('seleccionado');
        actualizarServiciosSeleccionados();
        return;
    }

    // Para servicios (selección múltiple)
    if (tipo === 'servicio') {
        elemento.classList.add('seleccionado');
        actualizarServiciosSeleccionados();
    } 
    // Para fechas/horarios (selección única)
    else {
        document.querySelectorAll(`.flotante.${tipo}`).forEach(el => {
            el.classList.remove('seleccionado');
        });
        elemento.classList.add('seleccionado');
        datosReserva[tipo] = elemento.querySelector('.p1').textContent;
        
        // Remover mensaje de error si se selecciona
        if (tipo === 'fecha') {
            document.getElementById('error-fecha').classList.remove('visible');
        } else if (tipo === 'horario') {
            document.getElementById('error-horario').classList.remove('visible');
        }
    }
}

function validarPaso(paso) {
    // Ocultar todos los mensajes primero
    document.querySelectorAll('.error-mensaje').forEach(msg => {
        msg.classList.remove('visible');
    });

    switch (paso) {
        case 1: 
            if (datosReserva.servicios.length === 0) {
                document.getElementById('error-servicio').classList.add('visible');
                return false;
            }
            return true;
            
        case 2:
            if (!datosReserva.fecha) {
                document.getElementById('error-fecha').classList.add('visible');
                return false;
            }
            return true;
            
        case 3:
            if (!datosReserva.horario) {
                document.getElementById('error-horario').classList.add('visible');
                return false;
            }
            return true;
            
        case 4:
            return validarFormulario();
            
        default:
            return true;
    }
}

function validarFormulario() {
    let valido = true;
    const nombre = document.getElementById('nombre').value.trim();
    const email = document.getElementById('email').value.trim();
    const telefono = document.getElementById('telefono').value.trim();
    
    // Ocultar todos los mensajes primero
    document.querySelectorAll('.error-mensaje').forEach(msg => {
        msg.classList.remove('visible');
    });
    
    // Validar nombre
    if (!nombre || nombre.length < 5) {
        document.getElementById('error-nombre').classList.add('visible');
        document.getElementById('nombre').classList.add('invalido');
        valido = false;
    }
    
    // Validar email
    if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
        document.getElementById('error-email').classList.add('visible');
        document.getElementById('email').classList.add('invalido');
        valido = false;
    }
    
    // Validar teléfono
    if (!telefono || !/^[0-9]{10}$/.test(telefono)) {
        document.getElementById('error-telefono').classList.add('visible');
        document.getElementById('telefono').classList.add('invalido');
        valido = false;
    }
    
    return valido;
}

function guardarDatosFormulario() {
    datosReserva.nombre = document.getElementById('nombre').value.trim();
    datosReserva.email = document.getElementById('email').value.trim();
    datosReserva.telefono = document.getElementById('telefono').value.trim();
    datosReserva.observacion = document.getElementById('observacion').value.trim() || 'Ninguna';
}

function actualizarResumen() {
    // Verificar que los elementos existen antes de acceder
    if (elementos.resumenNombre) {
        elementos.resumenNombre.textContent = datosReserva.nombre || "[No ingresado]";
    }
    
    const emailElement = document.getElementById('cliente-email');
    if (emailElement) {
        emailElement.textContent = datosReserva.email || "[No ingresado]";
    }
    
    if (elementos.resumenTelefono) {
        elementos.resumenTelefono.textContent = datosReserva.telefono || "[No ingresado]";
    }
    
    // Servicios seleccionados
    const listaServicios = datosReserva.servicios.length > 0
        ? datosReserva.servicios.map(s => `${s.nombre}`).join(", ")
        : "Ninguno seleccionado";
    elementos.resumenServicio.innerHTML = listaServicios;
    
    // Fecha y hora
    elementos.resumenFecha.textContent = datosReserva.fecha || "[No seleccionada]";
    elementos.resumenHorario.textContent = datosReserva.horario || "[No seleccionado]";
    elementos.resumenObservacion.textContent = datosReserva.observacion;
    
    // Cálculos de precios
    const subtotal = calcularSubtotal();
    const saldoPendiente = Math.max(0, subtotal - datosReserva.reserva); // No negativo
    
    document.getElementById('subtotal').textContent = `$${subtotal.toLocaleString()}`;
    document.getElementById('senia').textContent = `$${datosReserva.reserva.toLocaleString()}`;
    document.getElementById('saldo-pendiente').textContent = `$${saldoPendiente.toLocaleString()}`;
}

function validarNombre() {
    const input = document.getElementById('nombre');
    const errorMsg = document.getElementById('error-nombre');
    
    if (input.value.trim().length >= 5) {
        input.classList.remove('invalido');
        errorMsg.classList.remove('visible');
    } else {
        input.classList.add('invalido');
    }
}

function validarTelefono() {
    const input = document.getElementById('telefono');
    const errorMsg = document.getElementById('error-telefono');
    
    if (/^[0-9]{10}$/.test(input.value)) {
        input.classList.remove('invalido');
        errorMsg.classList.remove('visible');
    } else {
        input.classList.add('invalido');
    }
}

// Nueva función para validar email
function validarEmail() {
    const input = document.getElementById('email');
    const errorMsg = document.getElementById('error-email');
    
    if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(input.value)) {
        input.classList.remove('invalido');
        errorMsg.classList.remove('visible');
    } else {
        input.classList.add('invalido');
    }
}

function mostrarConfirmacion(exito) {
    // Ocultar todos los pasos
    elementos.pasos.forEach(paso => paso.classList.remove('activo'));
    
    // Mostrar paso de confirmación
    document.querySelector('.paso-6').classList.add('activo');
    
    // Mostrar el estado correspondiente
    if (exito) {
        document.querySelector('.paso-6 .exito').style.display = 'block';
        document.querySelector('.paso-6 .error').style.display = 'none';
        
        // Calcular el saldo pendiente
        const subtotal = datosReserva.servicios.reduce((total, servicio) => total + servicio.precio, 0);
        const saldoPendiente = Math.max(0, subtotal - datosReserva.reserva);
        
        // Mostrar resumen de la reserva con saldo pendiente
        const resumen = `
            <div class="resumen-confirmacion">
                <h3>Resumen de tu reserva</h3>
                <p><strong>Servicios:</strong> ${datosReserva.servicios.map(s => s.nombre).join(', ')}</p>
                <p><strong>Fecha:</strong> ${datosReserva.fecha}</p>
                <p><strong>Hora:</strong> ${datosReserva.horario}</p>
                <p><strong>Seña abonada:</strong> $${datosReserva.reserva.toLocaleString()}</p>
                <p class="total-confirmacion">Saldo pendiente: $${saldoPendiente.toLocaleString()}</p>
            </div>
        `;
        
        // Limpiar contenido previo y agregar el nuevo
        const exitoContainer = document.querySelector('.paso-6 .exito');
        exitoContainer.innerHTML = `
            <h2>¡Turno reservado!</h2>
            <p>Nos vemos en el local.</p>
        `;
        exitoContainer.insertAdjacentHTML('beforeend', resumen);
    } else {
        document.querySelector('.paso-6 .exito').style.display = 'none';
        document.querySelector('.paso-6 .error').style.display = 'block';
    }
    
    // Ocultar controles de navegación
    elementos.btnAnterior.style.display = 'none';
    elementos.btnSiguiente.style.display = 'none';
    
    // Opcional: Añadir botón para nueva reserva
    const botonNuevaReserva = `<button id="nueva-reserva" class="btn-reserva">Hacer otra reserva</button>`;
    document.querySelector('.paso-6').insertAdjacentHTML('beforeend', botonNuevaReserva);
    
    document.getElementById('nueva-reserva')?.addEventListener('click', () => {
        location.reload(); // Recarga la página para nueva reserva
    });
}

//////////////////////////////////////////
//////////// Autenticacion //////////////
/////////////////////////////////////////

function inicializarAuth() {
  const authContainer = document.querySelector('nav');
  if (!authContainer) return;

  // Crear botón si no existe
  if (!document.getElementById('btn-google')) {
    authContainer.innerHTML += '<button id="btn-google">Acceder</button>';
  }

  // Manejar estado de autenticación
  firebase.auth().onAuthStateChanged(user => {
    usuarioActual = user;
    const btnGoogle = document.getElementById('btn-google');
    
    if (user) {
      // Reemplazar botón con nombre
      btnGoogle.outerHTML = `<p class="usuario-nombre">${user.displayName}</p>`;
      guardarUsuario(user);
    } else {
      // Asegurarse que el botón existe
      if (!document.getElementById('btn-google')) {
        authContainer.innerHTML += '<button id="btn-google">Acceder</button>';
      }
      limpiarUsuario();
    }
  });

  // Delegación de eventos para el botón dinámico
  document.querySelector('nav').addEventListener('click', async (e) => {
    if (e.target.id === 'btn-google') {
      try {
        const provider = new firebase.auth.GoogleAuthProvider();
        await firebase.auth().signInWithPopup(provider);
      } catch (error) {
        console.error('Error de autenticación:', error);
        alert('Error al iniciar sesión: ' + error.message);
      }
    }
  });
}

// Función para mostrar errores de autenticación
function mostrarErrorAuth(error) {
  let mensaje = 'Error al autenticar';
  
  if (error.code === 'auth/popup-closed-by-user') {
    mensaje = 'El popup de autenticación fue cerrado';
  } else if (error.code === 'auth/cancelled-popup-request') {
    mensaje = 'Solicitud de autenticación cancelada';
  } else {
    mensaje = error.message || 'Error desconocido';
  }
  
  alert(mensaje); // O puedes mostrar esto en tu UI
}

// Guardar datos del usuario en LocalStorage
function guardarUsuario(user) {
  localStorage.setItem('usuario', JSON.stringify({
    uid: user.uid,
    nombre: user.displayName,
    email: user.email
  }));
}

// Limpiar datos del usuario
function limpiarUsuario() {
  localStorage.removeItem('usuario');
}

// Actualizar la UI con los datos del usuario
function actualizarUIUsuario(user) {
  const btnGoogle = document.getElementById('btn-google');
  if (!btnGoogle) return;

  // Cambiar el botón por un simple párrafo con el nombre
  btnGoogle.outerHTML = `<p class="usuario-nombre"></p>`;
  
  // Autocompletar formulario
  autocompletarFormulario(user);
}

function mostrarBotonLogin() {
  const contenedor = document.querySelector('nav h1').parentElement;
  if (!contenedor.querySelector('#btn-google')) {
    contenedor.innerHTML += '<button id="btn-google">Acceder</button>';
  }
}

function autocompletarFormulario(user) {
  // Solo autocompletar si estamos en el paso 4 y los campos existen
  const paso4 = document.querySelector('.paso-4');
  if (!paso4 || !paso4.classList.contains('activo') || !user) return;

  const nombreInput = document.getElementById('nombre');
  const emailInput = document.getElementById('email');
  
  if (nombreInput && !nombreInput.value) {
    nombreInput.value = user.displayName || '';
    validarNombre();
  }
  
  if (emailInput && !emailInput.value) {
    emailInput.value = user.email || '';
    validarEmail();
    datosReserva.email = user.email;
  }
}

